var divisibilityArray = function(word, m) {
    const res = [];
    let rem = 0;
    for (let i = 0; i < word.length; i++) {
        const digit = word.charCodeAt(i) - 48;
        rem = (rem * 10 + digit) % m;
        res.push(rem === 0 ? 1 : 0);
    }
    return res;
};
